15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRO — gauntlet canonical-onboarding-sequence fixture (§3 of release
18	// qualification)
19	//
20	// Each case walks the operator-facing onboarding handbook track for one
21	// vessel-construction mode, invoking the handbook's prescribed tabtargets
22	// in the prescribed order:
23	//
24	//   1. inscribe_reliquary — `rbw-dI` (depot-wide toolchain mirror)
25	//   2. ordain_conjure     — rbw-Odf walk: yoke + ordain rbev-sentry-deb-tether
26	//   3. ordain_airgap      — rbw-Oda walk: enshrine, conjure forge tethered,
27	//                            re-enshrine, conjure airgap from forge
28	//   4. ordain_bind        — rbw-Odb walk: ordain rbev-bottle-plantuml
29	//   5. ordain_graft       — rbw-Odg walk: docker pull, BURE_TWEAK override,
30	//                            ordain rbev-graft-demo
31	//
32	// Disposition: StateProgressing. Build-only — no charge, no test. Cases stop
33	// when each handbook-prescribed hallmark lands in GAR. Per-case precondition
34	// probes enable a-la-carte single-case rerun.
35	//
36	// The reliquary stamp captured by case 1 is persisted to a scratch file
37	// under .rbk/.gauntlet/ so cases 2 and 3 (the only cases that need it) can
38	// read it back without depending on case-1's BURV invocation context.
39	
40	use std::path::{Path, PathBuf};
41	
42	use crate::case;
43	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
44	use crate::rbtdrc_crucible::{rbtdrc_with_ctx, RBTDRC_FACT_HALLMARK, RBTDRC_FACT_RELIQUARY};
45	use crate::rbtdre_engine::{rbtdre_Disposition, rbtdre_Fixture, rbtdre_Section, rbtdre_Verdict};
46	use crate::rbtdri_invocation::{
47	    rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context, rbtdri_InvokeResult,
48	};
49	use crate::rbtdrk_canonical::rbtdrk_canonical_rbra;
50	use crate::rbtdrm_manifest::{
51	    RBTDRM_COLOPHON_ENSHRINE_VESSEL, RBTDRM_COLOPHON_INSCRIBE_RELIQUARY, RBTDRM_COLOPHON_ORDAIN,
52	    RBTDRM_COLOPHON_YOKE_RELIQUARY, RBTDRM_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE,
53	};
54	
55	// ── Vessel identities ────────────────────────────────────────
56	
57	/// Vessel directories passed positionally to global tabtargets (rbw-fO, rbw-dY).
58	const RBTDRO_VESSEL_DIR_CONJURE: &str = "rbev-vessels/rbev-sentry-deb-tether";
59	const RBTDRO_VESSEL_DIR_AIRGAP_FORGE: &str = "rbev-vessels/rbev-bottle-ifrit-forge";
60	const RBTDRO_VESSEL_DIR_AIRGAP: &str = "rbev-vessels/rbev-bottle-ifrit-airgap";
61	const RBTDRO_VESSEL_DIR_BIND: &str = "rbev-vessels/rbev-bottle-plantuml";
62	const RBTDRO_VESSEL_DIR_GRAFT: &str = "rbev-vessels/rbev-graft-demo";
63	
64	// ── Reliquary scratch state ──────────────────────────────────
65	
66	/// Fixture-private scratch path under the regime state dir. Carries the
67	/// reliquary stamp captured by case 1 forward to cases 2 and 3 across
68	/// per-case BURV-invocation isolation.
69	const RBTDRO_SCRATCH_RELIQUARY_REL: &str = ".rbk/.gauntlet/reliquary-stamp.txt";
70	
71	// ── Graft override ───────────────────────────────────────────
72	
73	/// BURE_TWEAK signal recognized by rbfd_FoundryDirectorBuild for graft mode:
74	/// supplies the local image reference without mutating the vessel rbrv.env.
75	const RBTDRO_GRAFT_TWEAK_NAME: &str = "threemodegraft";
76	
77	/// Source image for graft: any locally-resolvable docker image works; an
78	/// upstream public image keeps this case independent of the conjure case.
79	const RBTDRO_GRAFT_SOURCE_IMAGE: &str = "busybox:latest";
80	
81	// ── Probes ───────────────────────────────────────────────────
82	//
83	// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
84	// have no context, so they read the project root from current_dir() — theurge
85	// always launches from the project root.
86	
87	fn rbtdro_probe_root() -> Result<PathBuf, String> {
88	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
89	}
90	
91	fn rbtdro_scratch_reliquary_path(root: &Path) -> PathBuf {
92	    root.join(RBTDRO_SCRATCH_RELIQUARY_REL)
93	}
94	
95	/// Cases 1, 4, 5 probe: governor RBRA present at the canonical secrets path.
96	/// Established by canonical-establish §2 (rbtdrk_governor_mantle).
97	fn rbtdro_probe_governor_rbra() -> Result<(), String> {
98	    let root = rbtdro_probe_root()?;
99	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
100	    if !path.exists() {
101	        return Err(format!("governor RBRA absent at {}", path.display()));
102	    }
103	    Ok(())
104	}
105	
106	/// Cases 2 and 3 probe: reliquary stamp scratch file present and non-empty.
107	/// Established by case 1's inscribe; the scratch file lets per-vessel ordain
108	/// cases discover the stamp without re-walking depot inventory.
109	fn rbtdro_probe_reliquary_stamp() -> Result<(), String> {
110	    let root = rbtdro_probe_root()?;
111	    let path = rbtdro_scratch_reliquary_path(&root);
112	    let content = std::fs::read_to_string(&path)
113	        .map_err(|e| format!("reliquary scratch '{}' unreadable: {}", path.display(), e))?;
114	    if content.trim().is_empty() {
115	        return Err(format!("reliquary scratch '{}' is empty", path.display()));
116	    }
117	    Ok(())
118	}
119	
120	// ── Helpers ──────────────────────────────────────────────────
121	
122	fn rbtdro_invoke_logged(
123	    ctx: &mut rbtdri_Context,
124	    colophon: &str,
125	    args: &[&str],
126	    extra_env: &[(&str, &str)],
127	    dir: &Path,
128	    label: &str,
129	) -> Result<rbtdri_InvokeResult, String> {
130	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
131	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
132	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
133	    Ok(result)
134	}
135	
136	/// Run an ordain on `vessel_dir` and return the captured hallmark string.
137	/// Writes invocation logs to `dir` under the `label` prefix; returns Fail
138	/// verdict-bearing Err so callers can early-return cleanly.
139	fn rbtdro_ordain_capture(
140	    ctx: &mut rbtdri_Context,
141	    dir: &Path,
142	    vessel_dir: &str,
143	    extra_env: &[(&str, &str)],
144	    label: &str,
145	) -> Result<String, rbtdre_Verdict> {
146	    let result = match rbtdro_invoke_logged(
147	        ctx,
148	        RBTDRM_COLOPHON_ORDAIN,
149	        &[vessel_dir],
150	        extra_env,
151	        dir,
152	        label,
153	    ) {
154	        Ok(r) => r,
155	        Err(e) => {
156	            return Err(rbtdre_Verdict::Fail(format!(
157	                "ordain {} invocation: {}",
158	                vessel_dir, e
159	            )))
160	        }
161	    };
162	    if result.exit_code != 0 {
163	        return Err(rbtdre_Verdict::Fail(format!(
164	            "ordain {} exit {}\n{}",
165	            vessel_dir, result.exit_code, result.stderr
166	        )));
167	    }
168	    let hallmark = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_HALLMARK) {
169	        Ok(s) => s,
170	        Err(e) => {
171	            return Err(rbtdre_Verdict::Fail(format!(
172	                "read hallmark fact after ordain {}: {}",
173	                vessel_dir, e
174	            )))
175	        }
176	    };
177	    let _ = std::fs::write(dir.join(format!("{}-hallmark.txt", label)), &hallmark);
178	    Ok(hallmark)
179	}
180	
181	/// Yoke the reliquary stamp into a vessel's rbrv.env. The yoke tabtarget
182	/// validates the stamp and writes RBRV_RELIQUARY; the handbook ceremony
183	/// includes a commit step the operator performs by hand, which the fixture
184	/// skips since the yoke value is rerun-derivable from the scratch file.
185	fn rbtdro_yoke(
186	    ctx: &mut rbtdri_Context,
187	    dir: &Path,
188	    stamp: &str,
189	    vessel_dir: &str,
190	    label: &str,
191	) -> Result<(), rbtdre_Verdict> {
192	    let result = match rbtdro_invoke_logged(
193	        ctx,
194	        RBTDRM_COLOPHON_YOKE_RELIQUARY,
195	        &[stamp, vessel_dir],
196	        &[],
197	        dir,
198	        label,
199	    ) {
200	        Ok(r) => r,
201	        Err(e) => {
202	            return Err(rbtdre_Verdict::Fail(format!(
203	                "yoke {} invocation: {}",
204	                vessel_dir, e
205	            )))
206	        }
207	    };
208	    if result.exit_code != 0 {
209	        return Err(rbtdre_Verdict::Fail(format!(
210	            "yoke {} exit {}\n{}",
211	            vessel_dir, result.exit_code, result.stderr
212	        )));
213	    }
214	    Ok(())
215	}
216	
217	/// Sweep enshrine across all vessel rbrv.env files. Idempotent: already-
218	/// enshrined upstreams are skipped. The airgap chain calls this twice —
219	/// first to mirror the upstream rust base, then to populate the airgap
220	/// vessel's base anchor from the freshly-conjured forge hallmark.
221	fn rbtdro_enshrine(
222	    ctx: &mut rbtdri_Context,
223	    dir: &Path,
224	    label: &str,
225	) -> Result<(), rbtdre_Verdict> {
226	    let result = match rbtdro_invoke_logged(
227	        ctx,
228	        RBTDRM_COLOPHON_ENSHRINE_VESSEL,
229	        &[],
230	        &[],
231	        dir,
232	        label,
233	    ) {
234	        Ok(r) => r,
235	        Err(e) => return Err(rbtdre_Verdict::Fail(format!("enshrine invocation: {}", e))),
236	    };
237	    if result.exit_code != 0 {
238	        return Err(rbtdre_Verdict::Fail(format!(
239	            "enshrine exit {}\n{}",
240	            result.exit_code, result.stderr
241	        )));
242	    }
243	    Ok(())
244	}
245	
246	/// Pull a docker image. Used by the graft case to ensure the source image
247	/// is locally resolvable before the BURE_TWEAK-overridden ordain.
248	fn rbtdro_docker_pull(image_ref: &str) -> Result<(), String> {
249	    let output = std::process::Command::new("docker")
250	        .args(["pull", image_ref])
251	        .output()
252	        .map_err(|e| format!("docker pull exec failed: {}", e))?;
253	    if !output.status.success() {
254	        return Err(format!(
255	            "docker pull {} exited {}: {}",
256	            image_ref,
257	            output.status.code().unwrap_or(-1),
258	            String::from_utf8_lossy(&output.stderr).trim()
259	        ));
260	    }
261	    Ok(())
262	}
263	
264	// ── Case 1: inscribe-reliquary ───────────────────────────────
265	
266	/// Inscribe the depot-wide reliquary toolchain. Captures the reliquary
267	/// stamp from BURV fact, persists it to the fixture scratch file so
268	/// downstream conjure/airgap cases can yoke the same stamp into their
269	/// vessels without re-deriving it from depot inventory.
270	fn rbtdro_inscribe_reliquary(dir: &Path) -> rbtdre_Verdict {
271	    let probe = rbtdrb_Probe {
272	        name: "governor RBRA present",
273	        check: rbtdro_probe_governor_rbra,
274	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
275	    };
276	    if let Err(v) = rbtdrb_assert(&probe) {
277	        return v;
278	    }
279	    rbtdrc_with_ctx(|ctx| rbtdro_inscribe_reliquary_impl(ctx, dir))
280	}
281	
282	fn rbtdro_inscribe_reliquary_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
283	    let root = ctx.project_root().to_path_buf();
284	
285	    let result = match rbtdro_invoke_logged(
286	        ctx,
287	        RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
288	        &[],
289	        &[],
290	        dir,
291	        "inscribe",
292	    ) {
293	        Ok(r) => r,
294	        Err(e) => return rbtdre_Verdict::Fail(format!("inscribe invocation: {}", e)),
295	    };
296	    if result.exit_code != 0 {
297	        return rbtdre_Verdict::Fail(format!(
298	            "inscribe exit {}\n{}",
299	            result.exit_code, result.stderr
300	        ));
301	    }
302	
303	    let stamp = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_RELIQUARY) {
304	        Ok(s) => s,
305	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary fact: {}", e)),
306	    };
307	    let _ = std::fs::write(dir.join("reliquary-stamp.txt"), &stamp);
308	
309	    let scratch = rbtdro_scratch_reliquary_path(&root);
310	    if let Some(parent) = scratch.parent() {
311	        if let Err(e) = std::fs::create_dir_all(parent) {
312	            return rbtdre_Verdict::Fail(format!(
313	                "create scratch dir {}: {}",
314	                parent.display(),
315	                e
316	            ));
317	        }
318	    }
319	    if let Err(e) = std::fs::write(&scratch, &stamp) {
320	        return rbtdre_Verdict::Fail(format!(
321	            "write reliquary scratch {}: {}",
322	            scratch.display(),
323	            e
324	        ));
325	    }
326	    rbtdre_Verdict::Pass
327	}
328	
329	// ── Case 2: ordain-conjure (rbw-Odf walk) ────────────────────
330	
331	/// Yoke the reliquary stamp into rbev-sentry-deb-tether and ordain.
332	/// Mirrors rbw-Odf step 1 (yoke) and step 2 (ordain).
333	fn rbtdro_ordain_conjure(dir: &Path) -> rbtdre_Verdict {
334	    let probe = rbtdrb_Probe {
335	        name: "reliquary stamp captured",
336	        check: rbtdro_probe_reliquary_stamp,
337	        remediation: "rerun rbtdro_inscribe_reliquary before this case",
338	    };
339	    if let Err(v) = rbtdrb_assert(&probe) {
340	        return v;
341	    }
342	    rbtdrc_with_ctx(|ctx| rbtdro_ordain_conjure_impl(ctx, dir))
343	}
344	
345	fn rbtdro_ordain_conjure_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
346	    let root = ctx.project_root().to_path_buf();
347	    let stamp = match std::fs::read_to_string(rbtdro_scratch_reliquary_path(&root)) {
348	        Ok(s) => s.trim().to_string(),
349	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary scratch: {}", e)),
350	    };
351	
352	    if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, RBTDRO_VESSEL_DIR_CONJURE, "yoke-conjure") {
353	        return v;
354	    }
355	
356	    match rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_CONJURE, &[], "ordain-conjure") {
357	        Ok(_) => rbtdre_Verdict::Pass,
358	        Err(v) => v,
359	    }
360	}
361	
362	// ── Case 3: ordain-airgap (rbw-Oda walk) ─────────────────────
363	
364	/// Walk the airgap supply chain: enshrine upstream rust base, yoke the
365	/// reliquary into the forge vessel, conjure the forge tethered, re-enshrine
366	/// to populate the airgap vessel's base anchor from the freshly-built forge,
367	/// yoke the reliquary into the airgap vessel, conjure the airgap bottle.
368	/// Mirrors rbw-Oda steps 1-3.
369	fn rbtdro_ordain_airgap(dir: &Path) -> rbtdre_Verdict {
370	    let probe = rbtdrb_Probe {
371	        name: "reliquary stamp captured",
372	        check: rbtdro_probe_reliquary_stamp,
373	        remediation: "rerun rbtdro_inscribe_reliquary before this case",
374	    };
375	    if let Err(v) = rbtdrb_assert(&probe) {
376	        return v;
377	    }
378	    rbtdrc_with_ctx(|ctx| rbtdro_ordain_airgap_impl(ctx, dir))
379	}
380	
381	fn rbtdro_ordain_airgap_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
382	    let root = ctx.project_root().to_path_buf();
383	    let stamp = match std::fs::read_to_string(rbtdro_scratch_reliquary_path(&root)) {
384	        Ok(s) => s.trim().to_string(),
385	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary scratch: {}", e)),
386	    };
387	
388	    if let Err(v) = rbtdro_enshrine(ctx, dir, "enshrine-upstream") {
389	        return v;
390	    }
391	
392	    if let Err(v) = rbtdro_yoke(
393	        ctx,
394	        dir,
395	        &stamp,
396	        RBTDRO_VESSEL_DIR_AIRGAP_FORGE,
397	        "yoke-forge",
398	    ) {
399	        return v;
400	    }
401	    if let Err(v) =
402	        rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_AIRGAP_FORGE, &[], "ordain-forge")
403	    {
404	        return v;
405	    }
406	
407	    if let Err(v) = rbtdro_enshrine(ctx, dir, "enshrine-forge") {
408	        return v;
409	    }
410	
411	    if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, RBTDRO_VESSEL_DIR_AIRGAP, "yoke-airgap") {
412	        return v;
413	    }
414	    match rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_AIRGAP, &[], "ordain-airgap") {
415	        Ok(_) => rbtdre_Verdict::Pass,
416	        Err(v) => v,
417	    }
418	}
419	
420	// ── Case 4: ordain-bind (rbw-Odb walk) ───────────────────────
421	
422	/// Pin upstream PlantUML by digest. Bind mode reads RBRV_BIND_IMAGE from
423	/// rbev-bottle-plantuml/rbrv.env and mirrors the digest into GAR — no
424	/// reliquary, no Dockerfile, no Cloud Build. Mirrors rbw-Odb step 2.
425	/// (The handbook's step 1 readying a sentry hallmark is run-side and is
426	/// covered by canonical-establish leaving the conjured sentry from case 2.)
427	fn rbtdro_ordain_bind(dir: &Path) -> rbtdre_Verdict {
428	    let probe = rbtdrb_Probe {
429	        name: "governor RBRA present",
430	        check: rbtdro_probe_governor_rbra,
431	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
432	    };
433	    if let Err(v) = rbtdrb_assert(&probe) {
434	        return v;
435	    }
436	    rbtdrc_with_ctx(|ctx| rbtdro_ordain_bind_impl(ctx, dir))
437	}
438	
439	fn rbtdro_ordain_bind_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
440	    match rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_BIND, &[], "ordain-bind") {
441	        Ok(_) => rbtdre_Verdict::Pass,
442	        Err(v) => v,
443	    }
444	}
445	
446	// ── Case 5: ordain-graft (rbw-Odg walk) ──────────────────────
447	
448	/// Pull the graft source image, then ordain rbev-graft-demo with a
449	/// BURE_TWEAK overriding RBRV_GRAFT_IMAGE in-process. The override avoids
450	/// mutating rbev-graft-demo/rbrv.env so the fixture leaves no commit-worthy
451	/// regime drift behind. Mirrors rbw-Odg steps 1-2 (the handbook's docker
452	/// pull/tag + RBRV_GRAFT_IMAGE write fold into the BURE_TWEAK override).
453	fn rbtdro_ordain_graft(dir: &Path) -> rbtdre_Verdict {
454	    let probe = rbtdrb_Probe {
455	        name: "governor RBRA present",
456	        check: rbtdro_probe_governor_rbra,
457	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
458	    };
459	    if let Err(v) = rbtdrb_assert(&probe) {
460	        return v;
461	    }
462	    rbtdrc_with_ctx(|ctx| rbtdro_ordain_graft_impl(ctx, dir))
463	}
464	
465	fn rbtdro_ordain_graft_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
466	    if let Err(e) = rbtdro_docker_pull(RBTDRO_GRAFT_SOURCE_IMAGE) {
467	        return rbtdre_Verdict::Fail(format!(
468	            "docker pull {}: {}",
469	            RBTDRO_GRAFT_SOURCE_IMAGE, e
470	        ));
471	    }
472	    let extra_env: &[(&str, &str)] = &[
473	        ("BURE_TWEAK_NAME", RBTDRO_GRAFT_TWEAK_NAME),
474	        ("BURE_TWEAK_VALUE", RBTDRO_GRAFT_SOURCE_IMAGE),
475	    ];
476	    match rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_GRAFT, extra_env, "ordain-graft") {
477	        Ok(_) => rbtdre_Verdict::Pass,
478	        Err(v) => v,
479	    }
480	}
481	
482	// ── Section registry ─────────────────────────────────────────
483	
484	pub static RBTDRO_SECTIONS_CANONICAL_ONBOARDING_SEQUENCE: &[rbtdre_Section] = &[rbtdre_Section {
485	    name: "canonical-onboarding-arc",
486	    cases: &[
487	        case!(rbtdro_inscribe_reliquary),
488	        case!(rbtdro_ordain_conjure),
489	        case!(rbtdro_ordain_airgap),
490	        case!(rbtdro_ordain_bind),
491	        case!(rbtdro_ordain_graft),
492	    ],
493	}];
494	
495	pub static RBTDRO_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE: rbtdre_Fixture = rbtdre_Fixture {
496	    name: RBTDRM_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE,
497	    disposition: rbtdre_Disposition::StateProgressing,
498	    setup: None,
499	    teardown: None,
500	    sections: RBTDRO_SECTIONS_CANONICAL_ONBOARDING_SEQUENCE,
501	};
